SELECT
    id, line_no, rule_set_name, rule_set_no, first_no, first_type, second_no, second_type, combine, cond, threshold, result, version, deploy_at, is_valid, create_at
FROM rule_set


        line_no = #{param.lineNo}


        AND rule_set_name like CONCAT(#{param.ruleSetName}, '%')


        AND rule_set_no = #{param.ruleSetNo}


        AND is_valid = #{param.isValid}

    AND is_delete = 0

LIMIT #{start}, #{limit}

SELECT COUNT(*)
FROM rule_set


        line_no = #{param.lineNo}


        AND rule_set_name like CONCAT(#{param.ruleSetName}, '%')


        AND rule_set_no = #{param.ruleSetNo}


        AND is_valid = #{param.isValid}

    AND is_delete = 0

SELECT rule_set_no, rule_set_name, first_no, first_type, second_no, second_type, combine, cond, threshold, result, version, is_valid FROM rule_set WHERE rule_set_no IN
#{no}
AND is_delete = 0

